import os
import boto3
import joblib
from botocore.exceptions import ClientError

def load_latest_model():
    model_path = os.getenv('MODEL_PATH')
    if not model_path:
        raise ValueError("MODEL_PATH environment variable not set")
    
    if model_path.startswith('s3://'):
        return load_from_s3(model_path)
    else:
        return joblib.load(model_path)

def load_from_s3(model_path):
    s3 = boto3.client('s3')
    bucket, key = model_path[5:].split('/', 1)
    
    try:
        s3.download_file(bucket, key, '/tmp/latest_model')
        return joblib.load('/tmp/latest_model')
    except ClientError as e:
        raise Exception(f"Failed to download model from S3: {e}")

model = load_latest_model()